Rect dbBlock::getCoreArea()
{
  Rect rect;
  rect.mergeInit();

  for (dbRow* row : getRows()) {
    if (row->getSite()->getClass() != odb::dbSiteClass::PAD) {
      rect.merge(row->getBBox());
    }
  }

  if (!rect.isInverted()) {
    return rect;
  }

  // Default to die area if there aren't any rows.
  return getDieArea();
}

