void dbBlock::destroyCNs(std::vector<dbNet*>& nets, bool cleanExtid)
{
  std::vector<dbNet*>::iterator itr;

  for (itr = nets.begin(); itr != nets.end(); ++itr) {
    dbNet* net = *itr;
