{
  DIFF_BEGIN
  DIFF_FIELD(_flags._valid_bbox);
  DIFF_FIELD(_def_units);
  DIFF_FIELD(_dbu_per_micron);
  DIFF_FIELD(_hier_delimeter);
  DIFF_FIELD(_left_bus_delimeter);
