  DIFF_FIELD(_parent_block);
  DIFF_FIELD(_parent_inst);
  DIFF_FIELD(_top_module);

  if (!diff.deepDiff()) {
    DIFF_HASH_TABLE(_net_hash);
    DIFF_HASH_TABLE(_inst_hash);
    DIFF_HASH_TABLE(_module_hash);
    DIFF_HASH_TABLE(_modinst_hash);
