  for (auto modbterm : module->getModBTerms()) {
    block->_modbterm_tbl->destroy((_dbModBTerm*) modbterm);
  }

  for (auto modnet : module->getModNets()) {
    block->_modnet_tbl->destroy((_dbModNet*) modnet);
